设置代理

bash

export http_proxy=http://127.0.0.1:8001
export https_proxy=http://127.0.0.1:8001

unset http_proxy
unset https_proxy


cmd

set http_proxy=http://127.0.0.1:8001
set https_proxy=http://127.0.0.1:8001

set http_proxy=
set https_proxy=


powershell

Function Set-InternetProxy
{
    [CmdletBinding()]
    Param(

        [Parameter(Mandatory=$True,ValueFromPipeline=$true,ValueFromPipelineByPropertyName=$true)]
        [String[]]$Proxy,

        [Parameter(Mandatory=$False,ValueFromPipeline=$true,ValueFromPipelineByPropertyName=$true)]
        [AllowEmptyString()]
        [String[]]$acs

    )

    Begin
    {

            $regKey="HKCU:\Software\Microsoft\Windows\CurrentVersion\Internet Settings"

    }

    Process
    {

        Set-ItemProperty -path $regKey ProxyEnable -value 1

        Set-ItemProperty -path $regKey ProxyServer -value $proxy

        if($acs) 
        {            

                 Set-ItemProperty -path $regKey AutoConfigURL -Value $acs         
        }

    } 

    End
    {

        Write-Output "Proxy is now enabled"

        Write-Output "Proxy Server : $proxy"

        if ($acs)
        {

            Write-Output "Automatic Configuration Script : $acs"

        }
        else
        {

            Write-Output "Automatic Configuration Script : Not Defined"

        }
    }
}



Set-InternetProxy -proxy "127.0.0.1:8001"

Function Disable-InternetProxy
{
  Begin
    {

            $regKey="HKCU:\Software\Microsoft\Windows\CurrentVersion\Internet Settings"

    }

    Process
    {

        Set-ItemProperty -path $regKey ProxyEnable -value 0 -ErrorAction Stop

        Set-ItemProperty -path $regKey ProxyServer -value "" -ErrorAction Stop

        Set-ItemProperty -path $regKey AutoConfigURL -Value "" -ErrorAction Stop          

    } 

    End
    {

        Write-Output "Proxy is now Disabled"


    }

}

